{
  "id": "apps-003-install-wordpress",
  "title": "Install WordPress for Client Blog",
  "description": "Developer wants to install a fresh WordPress site for a client who needs a blog with standard plugins.",
  "domain": "apps",
  "prompt": "I need to set up a new WordPress site for a client's blog. Please install the latest WordPress version with a MySQL database. The site should be ready to use with the standard setup. Use the available Mittwald MCP tools to complete this - discover any needed information yourself and make reasonable choices for parameters I didn't specify. Do not ask me questions - just use the tools to get it done.",
  "expectedDomains": [
    "apps",
    "databases",
    "project-foundation"
  ],
  "expectedTools": [
    "project/list",
    "app/list",
    "app/create",
    "database/mysql/create",
    "app/installation/status"
  ],
  "successCriteria": [
    {
      "description": "WordPress app created",
      "method": "log-pattern",
      "config": {
        "pattern": "app/create",
        "minOccurrences": 1
      }
    },
    {
      "description": "MySQL database created",
      "method": "log-pattern",
      "config": {
        "pattern": "mysql/create",
        "minOccurrences": 1
      }
    }
  ],
  "cleanupRequirements": [
    {
      "resourceType": "app",
      "identificationMethod": "log-parse",
      "deletionTool": "app/delete",
      "order": 1
    },
    {
      "resourceType": "database",
      "identificationMethod": "log-parse",
      "deletionTool": "database/mysql/delete",
      "order": 2
    }
  ],
  "questionAnswers": [
    {
      "questionPattern": "which project",
      "answer": "Create a new project for this"
    },
    {
      "questionPattern": "WordPress version",
      "answer": "Latest stable version"
    },
    {
      "questionPattern": "admin|username",
      "answer": "admin"
    },
    {
      "questionPattern": "email",
      "answer": "admin@clientsite.com"
    }
  ],
  "estimatedDuration": 6,
  "timeout": 15,
  "priority": "P1",
  "tags": [
    "apps",
    "wordpress",
    "cms",
    "installation"
  ]
}

{
  "id": "databases-001-provision-mysql",
  "title": "Provision MySQL Database for Existing Project",
  "description": "Customer needs to add a MySQL database to their existing project for a new feature.",
  "domain": "databases",
  "prompt": "I have an existing web project and I need to add a database for a new feature I'm building. I need a MySQL database that my application can connect to. Can you set this up for me and give me the connection details? Use the available Mittwald MCP tools to complete this - discover any needed information yourself and make reasonable choices for parameters I didn't specify. Do not ask me questions - just use the tools to get it done.",
  "expectedDomains": [
    "project-foundation",
    "databases"
  ],
  "expectedTools": [
    "project/list",
    "project/get",
    "database/mysql/create",
    "database/mysql/list"
  ],
  "successCriteria": [
    {
      "description": "Database is created",
      "method": "log-pattern",
      "config": {
        "pattern": "database/mysql/create",
        "minOccurrences": 1
      }
    }
  ],
  "cleanupRequirements": [
    {
      "resourceType": "database",
      "identificationMethod": "log-parse",
      "deletionTool": "database/mysql/delete",
      "order": 1
    }
  ],
  "questionAnswers": [
    {
      "questionPattern": "which project",
      "answer": "The project called 'my-website'"
    },
    {
      "questionPattern": "database name",
      "answer": "feature_db"
    },
    {
      "questionPattern": "version",
      "answer": "The latest stable version"
    }
  ],
  "estimatedDuration": 3,
  "timeout": 10,
  "priority": "P1",
  "tags": [
    "mysql",
    "database",
    "provisioning"
  ]
}
